+// ─── Unified event queue ────────────────────────────────────────────────────
+
+type ProcessEvent =
+  | { kind: 'stdout'; line: string }
+  | { kind: 'stderr'; line: string }
+  | { kind: 'exit'; code: number | null; signal: string | null }
+  | { kind: 'error'; err: Error }
+  | { kind: 'timeout'; reason: 'first_event' | 'process' }
+  | { kind: 'abort' };
